int ksm(int a,int b=mod-2,int c=mod){

	int ans=1;

	while(b){

		if(b&1)ans=(LL)ans*a%mod;

		b>>=1;a=(LL)a*a%mod;

	}

	return ans;

}

int n,a,b,c[N],ans;

LL k;

